/* ---------------- THEME TOKENS ---------------- */
function useTheme(isDark) {
  return useMemo(() => ({
    isDark,
    bg: isDark ? "#111111" : "#F8F6F1",
    bgGradient: isDark
      ? "radial-gradient(1200px 600px at 15% -10%, rgba(34,180,85,0.16), transparent 60%), radial-gradient(900px 500px at 110% 10%, rgba(224,184,74,0.08), transparent 55%), #111111"
      : "radial-gradient(1200px 600px at 12% -10%, rgba(19,138,54,0.10), transparent 60%), radial-gradient(900px 500px at 110% 5%, rgba(216,161,43,0.08), transparent 55%), #F8F6F1",
    card: isDark ? "rgba(27,27,27,0.62)" : "rgba(255,255,255,0.18)",
    cardStrong: isDark ? "rgba(27,27,27,0.82)" : "rgba(255,255,255,0.55)",
    cardBorder: isDark ? "rgba(255,255,255,0.10)" : "rgba(255,255,255,0.45)",
    text: isDark ? "#FFFFFF" : "#222222",
    textMuted: isDark ? "#A6A6A6" : "#6B6B66",
    text2: isDark ? "#E3E3E3" : "#3C3C38",
    gold: isDark ? "#22B455" : "#138A36",
    goldSoft: isDark ? "#3ED676" : "#1FAE49",
    goldDeep: isDark ? "#17903F" : "#0E5F2A",
    ember: isDark ? "#E0B84A" : "#D8A12B",
    onyx: "#111111",
    divider: isDark ? "rgba(255,255,255,0.08)" : "rgba(34,34,34,0.08)",
    navBg: isDark ? "rgba(17,17,17,0.72)" : "rgba(255,255,255,0.55)",
    shadow: isDark
      ? "0 8px 32px rgba(0,0,0,0.5)"
      : "0 8px 28px rgba(34,34,34,0.10)",
  }), [isDark]);
}

/* ---------------- FONT INJECTION ---------------- */
function FontLoader() {
  useEffect(() => {
    const l = document.createElement("link");
    l.rel = "stylesheet";
    l.href = "https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800;900&display=swap";
    document.head.appendChild(l);
    return () => document.head.removeChild(l);
  }, []);
  return null;
}

const F_STACK = "'Inter', -apple-system, 'SF Pro Display', 'Helvetica Neue', sans-serif";
const F_DISPLAY = { fontFamily: F_STACK, fontWeight: 800, letterSpacing: "-0.02em" };
const F_BODY = { fontFamily: F_STACK };
const F_LABEL = { fontFamily: F_STACK, fontWeight: 600, letterSpacing: "0.12em", textTransform: "uppercase" };

/* ---------------- GLASS PRIMITIVES ---------------- */
function GlassPanel({ t, children, style, className = "", strong = false, onClick }) {
  const radius = (style && style.borderRadius) || 26;
  return (
    <div
      onClick={onClick}
      className={className}
      style={{
        position: "relative",
        overflow: "hidden",
        background: strong ? t.cardStrong : t.card,
        backdropFilter: "blur(28px) saturate(180%)",
        WebkitBackdropFilter: "blur(28px) saturate(180%)",
        border: `1px solid ${t.cardBorder}`,
        boxShadow: t.isDark
          ? `${t.shadow}, inset 0 1px 0 rgba(255,255,255,0.10), inset 0 -1px 0 rgba(0,0,0,0.25)`
          : `${t.shadow}, inset 0 1px 0 rgba(255,255,255,0.65), inset 0 -1px 0 rgba(20,60,35,0.05)`,
        borderRadius: 26,
        ...style,
      }}
    >
      <div
        aria-hidden="true"
        style={{
          position: "absolute", inset: 0, borderRadius: radius, pointerEvents: "none",
          background: t.isDark
            ? "linear-gradient(135deg, rgba(255,255,255,0.10) 0%, rgba(255,255,255,0.02) 30%, rgba(255,255,255,0) 55%)"
            : "linear-gradient(135deg, rgba(255,255,255,0.55) 0%, rgba(255,255,255,0.12) 35%, rgba(255,255,255,0) 60%)",
        }}
      />
      {children}
    </div>
  );
}

function GoldButton({ t, children, onClick, style, disabled, full }) {
  return (
    <button
      onClick={onClick}
      disabled={disabled}
      className={`flex items-center justify-center gap-2 transition-all active:scale-95 ${full ? "w-full" : ""}`}
      style={{
        background: disabled ? (t.isDark ? "#3a362a" : "#ded6bb") : `linear-gradient(135deg, ${t.goldSoft}, ${t.gold} 55%, ${t.goldDeep})`,
        color: disabled ? t.textMuted : "#FFFFFF",
        fontWeight: 700,
        padding: "15px 24px",
        borderRadius: 999,
        boxShadow: disabled ? "none" : "0 10px 26px rgba(19,138,54,0.35)",
        ...F_BODY,
        ...style,
      }}
    >
      {children}
    </button>
  );
}

function GhostButton({ t, children, onClick, style, full }) {
  return (
    <button
      onClick={onClick}
      className={`flex items-center justify-center gap-2 transition-all active:scale-95 ${full ? "w-full" : ""}`}
      style={{
        background: t.card,
        backdropFilter: "blur(18px) saturate(160%)",
        WebkitBackdropFilter: "blur(18px) saturate(160%)",
        color: t.gold,
        fontWeight: 600,
        padding: "14px 22px",
        borderRadius: 999,
        border: `1.5px solid ${t.gold}`,
        ...F_BODY,
        ...style,
      }}
    >
      {children}
    </button>
  );
}

function Pill({ t, active, children, onClick }) {
  return (
    <button
      onClick={onClick}
      className="whitespace-nowrap transition-all active:scale-95"
      style={{
        ...F_LABEL,
        fontSize: 11,
        padding: "10px 16px",
        borderRadius: 999,
        background: active ? `linear-gradient(135deg, ${t.goldSoft}, ${t.gold})` : t.card,
        color: active ? "#FFFFFF" : t.text2,
        border: `1px solid ${active ? "transparent" : t.cardBorder}`,
        backdropFilter: "blur(20px) saturate(160%)",
      }}
    >
      {children}
    </button>
  );
}

function ScreenHeader({ t, title, subtitle, onBack, right }) {
  return (
    <div className="flex items-center justify-between px-5 pt-14 pb-4">
      <div className="flex items-center gap-3">
        {onBack && (
          <button onClick={onBack} className="active:scale-90 transition-transform" style={{ color: t.text }}>
            <ChevronLeft size={26} />
          </button>
        )}
        <div>
          <div style={{ ...F_DISPLAY, fontSize: 22, color: t.text, fontWeight: 600 }}>{title}</div>
          {subtitle && <div style={{ ...F_BODY, fontSize: 12.5, color: t.textMuted, marginTop: 2 }}>{subtitle}</div>}
        </div>
      </div>
      {right}
    </div>
  );
}

