/* ============================================================
   SPLASH SCREEN
   ============================================================ */
function Splash({ t, onDone }) {
  const [stage, setStage] = useState(0);
  useEffect(() => {
    const timers = [
      setTimeout(() => setStage(1), 200),
      setTimeout(() => setStage(2), 1600),
      setTimeout(() => setStage(3), 2300),
      setTimeout(() => onDone(), 3300),
    ];
    return () => timers.forEach(clearTimeout);
  }, []);

  const SIZE = 220;
  const CELL = 100 / 3;
  // 3x3 shard grid — each piece explodes outward from center then reassembles
  const shards = [];
  for (let row = 0; row < 3; row++) {
    for (let col = 0; col < 3; col++) {
      const cx = col - 1; // -1, 0, 1
      const cy = row - 1;
      const mag = 130 + ((row + col) % 3) * 22;
      const dx = cx === 0 ? (col === 1 && row !== 1 ? 0 : 14) : cx * mag;
      const dy = cy === 0 ? 0 : cy * mag;
      const rot = ((row * 3 + col) % 2 === 0 ? -1 : 1) * (18 + ((row + col) * 7) % 26);
      const left = col * CELL;
      const right = col === 2 ? 100 : (col + 1) * CELL;
      const top = row * CELL;
      const bottom = row === 2 ? 100 : (row + 1) * CELL;
      shards.push({
        key: `${row}-${col}`,
        clip: `polygon(${left}% ${top}%, ${right}% ${top}%, ${right}% ${bottom}%, ${left}% ${bottom}%)`,
        dx, dy, rot,
        delay: ((row * 3 + col) % 9) * 0.035,
      });
    }
  }

  return (
    <div className="fixed inset-0 flex items-center justify-center" style={{ background: "radial-gradient(720px 520px at 50% 42%, #16401F, #111111 75%)", opacity: stage === 3 ? 0 : 1, transition: "opacity 1s ease" }}>
      <div className="relative flex flex-col items-center justify-center" style={{ width: 320, height: 300 }}>
        <div
          className="relative"
          style={{
            width: SIZE,
            height: SIZE,
            filter: stage >= 2 ? "drop-shadow(0 0 30px rgba(34,180,85,0.65)) drop-shadow(0 0 60px rgba(224,184,74,0.35))" : "none",
            transition: "filter 1s ease",
          }}
        >
          {shards.map((s) => (
            <img
              key={s.key}
              src={LOGO_URI}
              alt=""
              draggable={false}
              style={{
                position: "absolute", inset: 0, width: "100%", height: "100%",
                objectFit: "contain",
                clipPath: s.clip,
                WebkitClipPath: s.clip,
                transform: stage >= 1
                  ? "translate(0px, 0px) rotate(0deg) scale(1)"
                  : `translate(${s.dx}px, ${s.dy}px) rotate(${s.rot}deg) scale(0.7)`,
                opacity: stage >= 1 ? 1 : 0,
                transition: `all 1.05s cubic-bezier(0.16,1,0.3,1) ${s.delay}s`,
              }}
            />
          ))}
        </div>
        <div
          style={{
            marginTop: 20,
            ...F_LABEL,
            fontSize: 11,
            color: "#8FD9A3",
            opacity: stage >= 2 ? 1 : 0,
            transition: "opacity 0.8s ease 0.4s",
            whiteSpace: "nowrap",
          }}
        >
          Garden-to-Table Dining
        </div>
      </div>
    </div>
  );
}

/* ============================================================
   AUTH
   ============================================================ */
function Auth({ t, onAuth }) {
  const [mode, setMode] = useState("login"); // login | signup | forgot
  const [form, setForm] = useState({ name: "", email: "", phone: "", password: "" });
  const [optIn, setOptIn] = useState(true);
  const [sent, setSent] = useState(false);
  const [guestNotice, setGuestNotice] = useState(false);
  const [bgIndex, setBgIndex] = useState(0);

  // Forgot-password flow: details -> pin -> reset -> done
  const [forgotStep, setForgotStep] = useState("details");
  const [forgotEmail, setForgotEmail] = useState("");
  const [forgotPhone, setForgotPhone] = useState("");
  const [sentPin, setSentPin] = useState("");
  const [enteredPin, setEnteredPin] = useState("");
  const [pinError, setPinError] = useState("");
  const [newPassword, setNewPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [resetError, setResetError] = useState("");

  const resetForgotFlow = () => {
    setForgotStep("details"); setForgotEmail(""); setForgotPhone(""); setSentPin("");
    setEnteredPin(""); setPinError(""); setNewPassword(""); setConfirmPassword(""); setResetError("");
  };

  useEffect(() => {
    const iv = setInterval(() => setBgIndex((i) => (i + 1) % AUTH_BG_IMAGES.length), 4500);
    return () => clearInterval(iv);
  }, []);

  return (
    <div className="min-h-screen flex flex-col justify-end px-5 pb-10 relative overflow-hidden">
      {AUTH_BG_IMAGES.map((src, i) => (
        <img
          key={i}
          src={src}
          alt=""
          style={{
            position: "absolute", inset: 0, width: "100%", height: "100%", objectFit: "cover",
            opacity: i === bgIndex ? 1 : 0,
            transform: i === bgIndex ? "scale(1.06)" : "scale(1)",
            transition: "opacity 1.6s ease, transform 9s ease-in-out",
            zIndex: 0,
          }}
        />
      ))}
      <div style={{ position: "absolute", inset: 0, background: `linear-gradient(180deg, rgba(17,17,17,0.25), ${t.onyx} 78%)`, zIndex: 1 }} />
      <div className="relative" style={{ zIndex: 2 }}>
      <div className="mb-8 flex items-end gap-4">
        <img src={LOGO_URI} alt="Zone Garden" style={{ width: 72, height: 72, borderRadius: "50%", objectFit: "cover", boxShadow: "0 8px 24px rgba(0,0,0,0.35)", border: "2px solid rgba(255,255,255,0.25)" }} />
        <div>
          <div style={{ ...F_LABEL, fontSize: 11, color: "#3ED676" }}>Welcome to</div>
          <div style={{ ...F_DISPLAY, fontSize: 34, color: "#F3EFE6", fontWeight: 700, marginTop: 2, lineHeight: 1.05 }}>Zone Garden</div>
          <div style={{ ...F_BODY, fontSize: 12.5, color: "#C8C3B6", marginTop: 3 }}>Garden-to-Table Dining · Borrowdale</div>
        </div>
      </div>

      <GlassPanel t={{ ...t, isDark: true }} strong style={{ padding: 22 }}>
        {mode !== "forgot" && (
          <div className="flex gap-2 mb-5">
            {["login", "signup"].map((m) => (
              <button
                key={m}
                onClick={() => setMode(m)}
                className="flex-1 py-2 rounded-xl transition-all"
                style={{
                  ...F_LABEL, fontSize: 11,
                  background: mode === m ? "linear-gradient(135deg,#3ED676,#17903F)" : "transparent",
                  color: mode === m ? "#FFFFFF" : "#C8C3B6",
                }}
              >
                {m === "login" ? "Log In" : "Sign Up"}
              </button>
            ))}
          </div>
        )}

        {mode === "forgot" ? (
          <div className="flex flex-col gap-3">
            {forgotStep === "details" && (
              <>
                <div style={{ ...F_BODY, fontSize: 13, color: "#C8C3B6" }}>Enter your email and phone number — we'll send a verification PIN.</div>
                <AuthInput dark placeholder="Email address" value={forgotEmail} onChange={setForgotEmail} />
                <AuthInput dark placeholder="Phone number" value={forgotPhone} onChange={setForgotPhone} />
                <GoldButton
                  t={t} full
                  disabled={!forgotEmail.trim() || !forgotPhone.trim()}
                  onClick={() => {
                    const pin = String(Math.floor(1000 + Math.random() * 9000));
                    setSentPin(pin);
                    setForgotStep("pin");
                  }}
                >
                  Send PIN
                </GoldButton>
                <button onClick={() => { setMode("login"); resetForgotFlow(); }} style={{ ...F_LABEL, fontSize: 11, color: "#C8C3B6", marginTop: 4 }}>Back</button>
              </>
            )}

            {forgotStep === "pin" && (
              <>
                <div style={{ ...F_BODY, fontSize: 13, color: "#C8C3B6" }}>
                  We sent a 4-digit PIN to <strong style={{ color: "#F3EFE6" }}>{forgotEmail}</strong> and <strong style={{ color: "#F3EFE6" }}>{forgotPhone}</strong>. Enter it below.
                </div>
                <div style={{ ...F_BODY, fontSize: 11, color: "#3ED676" }}>Demo PIN (no SMS/email service connected): {sentPin}</div>
                <AuthInput dark placeholder="4-digit PIN" value={enteredPin} onChange={(v) => { setEnteredPin(v.replace(/\D/g, "").slice(0, 4)); setPinError(""); }} />
                {pinError && <div style={{ ...F_BODY, fontSize: 11.5, color: "#FF8A80" }}>{pinError}</div>}
                <GoldButton
                  t={t} full
                  disabled={enteredPin.length !== 4}
                  onClick={() => {
                    if (enteredPin === sentPin) { setForgotStep("reset"); setPinError(""); }
                    else setPinError("Incorrect PIN — please try again.");
                  }}
                >
                  Verify PIN
                </GoldButton>
                <button
                  onClick={() => { const pin = String(Math.floor(1000 + Math.random() * 9000)); setSentPin(pin); setEnteredPin(""); setPinError(""); }}
                  style={{ ...F_LABEL, fontSize: 10, color: "#3ED676" }}
                >
                  Resend PIN
                </button>
                <button onClick={() => { setForgotStep("details"); setEnteredPin(""); setPinError(""); }} style={{ ...F_LABEL, fontSize: 11, color: "#C8C3B6", marginTop: 2 }}>Back</button>
              </>
            )}

            {forgotStep === "reset" && (
              <>
                <div style={{ ...F_BODY, fontSize: 13, color: "#C8C3B6" }}>PIN verified. Set a new password.</div>
                <AuthInput dark placeholder="New password" type="password" value={newPassword} onChange={(v) => { setNewPassword(v); setResetError(""); }} />
                <AuthInput dark placeholder="Confirm new password" type="password" value={confirmPassword} onChange={(v) => { setConfirmPassword(v); setResetError(""); }} />
                {resetError && <div style={{ ...F_BODY, fontSize: 11.5, color: "#FF8A80" }}>{resetError}</div>}
                <GoldButton
                  t={t} full
                  disabled={!newPassword || !confirmPassword}
                  onClick={() => {
                    if (newPassword.length < 4) { setResetError("Password must be at least 4 characters."); return; }
                    if (newPassword !== confirmPassword) { setResetError("Passwords don't match."); return; }
                    setForgotStep("done");
                  }}
                >
                  Reset Password
                </GoldButton>
              </>
            )}

            {forgotStep === "done" && (
              <div className="text-center py-4">
                <Check size={30} color="#3ED676" className="mx-auto mb-2" />
                <div style={{ ...F_BODY, color: "#F3EFE6", fontSize: 14 }}>Password reset. You can now log in.</div>
                <button onClick={() => { setMode("login"); resetForgotFlow(); }} style={{ ...F_LABEL, fontSize: 11, color: "#3ED676", marginTop: 14 }}>Back to Log In</button>
              </div>
            )}
          </div>
        ) : (
          <div className="flex flex-col gap-3">
            {mode === "signup" && <AuthInput dark placeholder="Full name" value={form.name} onChange={(v) => setForm({ ...form, name: v })} />}
            <AuthInput dark placeholder="Email address" value={form.email} onChange={(v) => setForm({ ...form, email: v })} />
            {mode === "signup" && <AuthInput dark placeholder="Phone number" value={form.phone} onChange={(v) => setForm({ ...form, phone: v })} />}
            <AuthInput dark placeholder="Password" type="password" value={form.password} onChange={(v) => setForm({ ...form, password: v })} />

            {mode === "signup" && (
              <label className="flex items-start gap-2 mt-1" style={{ ...F_BODY, fontSize: 12, color: "#C8C3B6" }}>
                <input type="checkbox" checked={optIn} onChange={(e) => setOptIn(e.target.checked)} style={{ marginTop: 3 }} />
                Send me promotions, loyalty rewards, restaurant updates and birthday offers by email.
              </label>
            )}

            {mode === "login" && (
              <button onClick={() => { setMode("forgot"); resetForgotFlow(); }} className="self-end" style={{ ...F_LABEL, fontSize: 10.5, color: "#3ED676" }}>Forgot password?</button>
            )}

            <GoldButton t={t} full style={{ marginTop: 6 }} onClick={() => onAuth({ name: form.name || "Guest Diner", email: form.email, guest: false })}>
              {mode === "login" ? "Log In" : "Create Account"}
            </GoldButton>
            <GhostButton t={{ ...t, text: "#F3EFE6", cardBorder: "rgba(255,255,255,0.18)" }} full onClick={() => onAuth({ name: "Guest", email: "", guest: true })}>
              Continue as Guest
            </GhostButton>
            <div style={{ ...F_BODY, fontSize: 10.5, color: "#9A968B", textAlign: "center", marginTop: 2 }}>
              Guest orders are limited to 1 item, with loyalty points and coupons locked.
            </div>
          </div>
        )}
      </GlassPanel>
      </div>
    </div>
  );
}

function AuthInput({ placeholder, value, onChange, type = "text", dark }) {
  return (
    <>
      <style>{`.auth-gold-input::placeholder { color: ${dark ? "rgba(232,206,138,0.45)" : "rgba(28,27,25,0.4)"}; }`}</style>
      <input
        className="auth-gold-input"
        type={type}
        placeholder={placeholder}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        style={{
          ...F_BODY,
          background: dark ? "rgba(255,255,255,0.07)" : "rgba(0,0,0,0.04)",
          border: `1px solid ${dark ? "rgba(224,184,74,0.28)" : "rgba(0,0,0,0.08)"}`,
          borderRadius: 14,
          padding: "13px 15px",
          color: dark ? "#E8CE8A" : "#1C1B19",
          caretColor: dark ? "#E0B84A" : "#1C1B19",
          fontSize: 14,
          outline: "none",
        }}
      />
    </>
  );
}

