/* ============================================================
   NAV + CART FAB
   ============================================================ */
function BottomNav({ t, tab, setTab, cartCount }) {
  const tabs = [
    { id: "home", icon: Home, label: "Home" },
    { id: "menu", icon: UtensilsCrossed, label: "Menu" },
    { id: "orders", icon: ClipboardList, label: "Orders" },
    { id: "cart", icon: ShoppingBag, label: "Cart" },
    { id: "profile", icon: User, label: "Profile" },
  ];
  return (
    <div className="fixed left-4 right-4 flex justify-around items-center" style={{ bottom: 18, height: 68, borderRadius: 28, background: t.navBg, backdropFilter: "blur(32px) saturate(180%)", WebkitBackdropFilter: "blur(32px) saturate(180%)", border: `1px solid ${t.cardBorder}`, boxShadow: t.shadow }}>
      {tabs.map((tb) => {
        const Icon = tb.icon;
        const active = tab === tb.id;
        return (
          <button key={tb.id} onClick={() => setTab(tb.id)} className="flex flex-col items-center gap-1 relative transition-transform active:scale-90" style={{ width: 54 }}>
            {active && <div style={{ position: "absolute", top: -14, width: 34, height: 3, borderRadius: 999, background: `linear-gradient(90deg, ${t.goldSoft}, ${t.gold})` }} />}
            <Icon size={20} color={active ? t.gold : t.textMuted} strokeWidth={active ? 2.4 : 2} />
            {tb.id === "cart" && cartCount > 0 && (
              <span className="absolute flex items-center justify-center" style={{ top: -6, right: 6, width: 16, height: 16, borderRadius: 999, background: t.ember, color: "#fff", fontSize: 9, fontWeight: 700 }}>{cartCount}</span>
            )}
            <span style={{ ...F_LABEL, fontSize: 8.5, color: active ? t.gold : t.textMuted, letterSpacing: "0.06em" }}>{tb.label}</span>
          </button>
        );
      })}
    </div>
  );
}

/* ============================================================
   ROOT APP
   ============================================================ */
export default function App() {
  const [phase, setPhase] = useState("splash"); // splash | auth | app
  const [isDark, setIsDark] = useState(() => {
    if (typeof window !== "undefined" && window.matchMedia) {
      return window.matchMedia("(prefers-color-scheme: dark)").matches;
    }
    return false;
  });

  useEffect(() => {
    if (typeof window === "undefined" || !window.matchMedia) return;
    const mq = window.matchMedia("(prefers-color-scheme: dark)");
    const handler = (e) => setIsDark(e.matches);
    mq.addEventListener ? mq.addEventListener("change", handler) : mq.addListener(handler);
    return () => {
      mq.removeEventListener ? mq.removeEventListener("change", handler) : mq.removeListener(handler);
    };
  }, []);

  const t = useTheme(isDark);

  const [tab, setTab] = useState("home");
  const [user, setUser] = useState(null);
  const [view, setView] = useState({ name: "home" }); // stacked view within a tab
  const [stack, setStack] = useState([]);

  const [cart, setCart] = useState([]);
  const [favorites, setFavorites] = useState([]);
  const [orders, setOrders] = useState([]);
  const [points, setPoints] = useState(140);
  const [promo, setPromo] = useState("");
  const [promoApplied, setPromoApplied] = useState(false);
  const [notes, setNotes] = useState("");
  const [checkoutTotal, setCheckoutTotal] = useState(0);
  const [lastOrder, setLastOrder] = useState(null);
  const [notice, setNotice] = useState(null);

  const showNotice = (msg) => {
    setNotice(msg);
    setTimeout(() => setNotice((n) => (n === msg ? null : n)), 2800);
  };

  const push = (v) => { setStack((s) => [...s, view]); setView(v); };
  const back = () => { setStack((s) => { const n = [...s]; const prev = n.pop(); setView(prev || { name: "home" }); return n; }); };

  const openItem = (item) => push({ name: "item", item });
  const openCategory = (cat, items) => push({ name: "category", cat, items });
  const toggleFav = (id) => setFavorites((f) => (f.includes(id) ? f.filter((x) => x !== id) : [...f, id]));

  const addToCart = (item, qty, addons, instructions) => {
    const currentCount = cart.reduce((s, c) => s + c.qty, 0);
    if (user?.guest && currentCount >= 1) {
      showNotice("Guest orders are limited to 1 item — log in or sign up to order more.");
      return;
    }
    const cappedQty = user?.guest ? 1 : qty;
    setCart((c) => [...c, { item, qty: cappedQty, addons, instructions }]);
    back();
    setTab("cart");
    setView({ name: "home" });
    setStack([]);
  };
  const updateQty = (idx, delta) => setCart((c) => c.map((x, i) => {
    if (i !== idx) return x;
    if (user?.guest && delta > 0) { showNotice("Guest orders are limited to 1 item — log in or sign up to order more."); return x; }
    return { ...x, qty: Math.max(1, x.qty + delta) };
  }));
  const removeItem = (idx) => setCart((c) => c.filter((_, i) => i !== idx));
  const applyPromo = () => { if (promo.trim().toUpperCase() === "ZONE20") setPromoApplied(true); };

  const goCheckout = (total) => { setCheckoutTotal(total); push({ name: "checkout" }); };

  const placeOrder = (info) => {
    const number = 2000 + Math.floor(Math.random() * 900);
    const itemLines = cart.map((c) => `• ${c.item.name} x${c.qty}${c.addons.length ? ` (${c.addons.map((a) => a.n).join(", ")})` : ""}`).join("\n");
    const msg =
`Order #${number}

Customer:
${user?.name || "Guest"}

Phone:
${info.phone || "-"}

Fulfillment:
${info.fulfillment === "delivery" ? `Delivery — ${info.address || "-"}` : info.fulfillment === "pickup" ? "Pickup at Zone Garden" : `Dine-In — ${info.reserveTime || "-"}`}

Items
${itemLines}

Total:
US$${checkoutTotal.toFixed(2)}

Payment:
${info.payment === "ecocash" ? "EcoCash" : "Cash on Delivery"}

Special Instructions:
${notes || info.dnotes || "None"}`;

    window.open(`https://wa.me/${RESTAURANT_WHATSAPP}?text=${encodeURIComponent(msg)}`, "_blank");

    const orderRecord = { number, total: checkoutTotal, prepTime: "25–35 min", payment: info.payment, fulfillment: info.fulfillment, date: "Today", items: cart };
    setOrders((o) => [orderRecord, ...o]);
    setPoints((p) => (user?.guest ? p : p + Math.round(checkoutTotal)));
    setLastOrder(orderRecord);
    setCart([]); setNotes(""); setPromo(""); setPromoApplied(false);
    push({ name: "confirmation", order: orderRecord });
  };

  const resetToHome = () => { setStack([]); setView({ name: "home" }); setTab("home"); };

  if (phase === "splash") return (<><FontLoader /><Splash t={t} onDone={() => setPhase("auth")} /></>);
  if (phase === "auth") return (
    <>
      <FontLoader />
      <Auth t={t} onAuth={(u) => { setUser(u); setPhase("app"); }} />
    </>
  );

  const cartCount = cart.reduce((s, c) => s + c.qty, 0);

  const quickAdd = (item) => addToCart(item, 1, [], "");

  let screen = null;
  if (view.name === "item") {
    screen = <FoodDetail t={t} item={view.item} onBack={back} onAddToCart={addToCart} favorites={favorites} toggleFav={toggleFav} onOpenItem={openItem} />;
  } else if (view.name === "category") {
    screen = <CategoryList t={t} category={view.cat} items={view.items} onBack={back} onOpenItem={openItem} favorites={favorites} toggleFav={toggleFav} onQuickAdd={quickAdd} />;
  } else if (view.name === "checkout") {
    screen = <Checkout t={t} total={checkoutTotal} onBack={back} onPlaceOrder={placeOrder} user={user} />;
  } else if (view.name === "confirmation") {
    screen = <Confirmation t={t} order={view.order} onDone={resetToHome} />;
  } else if (view.name === "profileSub") {
    screen = <ProfileSub t={t} which={view.which} onBack={back} favorites={favorites} onOpenItem={openItem} points={points} user={user} showNotice={showNotice} />;
  } else {
    if (tab === "home") screen = <HomeScreen t={t} onOpenItem={openItem} onOpenCategory={openCategory} favorites={favorites} toggleFav={toggleFav} onSearch={() => {}} onOrderNow={() => setTab("menu")} onQuickAdd={quickAdd} />;
    else if (tab === "menu") screen = <Menu t={t} onOpenCategory={openCategory} />;
    else if (tab === "orders") screen = <Orders t={t} orders={orders} onReorder={(o) => setCart(o.items)} />;
    else if (tab === "cart") screen = <Cart t={t} cart={cart} updateQty={updateQty} removeItem={removeItem} promo={promo} setPromo={setPromo} promoApplied={promoApplied} applyPromo={applyPromo} onCheckout={goCheckout} notes={notes} setNotes={setNotes} user={user} />;
    else if (tab === "profile") screen = <Profile t={t} user={user} points={points} favorites={favorites} onOpenSub={(which) => push({ name: "profileSub", which })} onLogout={() => { setPhase("auth"); setUser(null); resetToHome(); }} isDark={isDark} setIsDark={setIsDark} />;
  }

  return (
    <div style={{ minHeight: "100vh", background: t.bgGradient, ...F_BODY, transition: "background 0.4s ease" }}>
      <FontLoader />
      <div style={{ maxWidth: 480, margin: "0 auto", position: "relative" }}>
        {screen}
        {view.name !== "item" && view.name !== "checkout" && view.name !== "confirmation" && (
          <BottomNav t={t} tab={tab} setTab={(tb) => { setTab(tb); setView({ name: "home" }); setStack([]); }} cartCount={cartCount} />
        )}
        {notice && (
          <div style={{ position: "fixed", left: 16, right: 16, bottom: 100, zIndex: 50, maxWidth: 448, margin: "0 auto" }}>
            <GlassPanel t={t} strong style={{ padding: "12px 16px" }}>
              <span style={{ ...F_BODY, fontSize: 12.5, color: t.text }}>{notice}</span>
            </GlassPanel>
          </div>
        )}
      </div>
    </div>
  );
}
